            ContentJson = """{"title":"Time Tracking Field Reference","groups":[{"heading":"Start Timer Fields","items":[{"label":"Category (optional)","value":"Pick a work category — None, Production, Setup, Inspection, Maintenance, Training, Meeting, Admin, Cleanup, or Other. Starts on None."},{"label":"Notes (optional)","value":"A short note about what you're working on. You can update it when you stop the timer."}]},{"heading":"Stop Timer Fields","items":[{"label":"Timer running for","value":"Shows how long the timer has run, like '1h 23m', plus the category if you set one. Just for reference — you can't edit it."},{"label":"Notes (optional)","value":"Add or update a note as you stop the timer."}]},{"heading":"Manual Entry Fields","items":[{"label":"Date (required)","value":"The day this time was worked. Starts on today."},{"label":"Category (optional)","value":"Same category choices as the timer. Starts on None."},{"label":"Hours (required)","value":"Whole hours worked, 0 to 24. Combines with Minutes for the total."},{"label":"Minutes (required)","value":"Extra minutes worked, 0 to 59. Combines with Hours. The total must be more than zero."},{"label":"Notes (optional)","value":"A short description of the work you did."}]},{"heading":"Date Filter","items":[{"label":"From","value":"Shows only entries on or after this date. Leave blank for no start limit."},{"label":"To","value":"Shows only entries on or before this date. Leave blank for no end limit."},{"label":"Summary line","value":"Total hours and how many entries match your filter, like '12.5 hours across 8 entries'."}]},{"heading":"Table Columns","items":[{"label":"Icon","value":"A small icon marks each entry: a lit-up timer for a running one, a plain timer for a finished one, or a pencil for a manual entry."},{"label":"Date","value":"The day the time was worked, shown as MM/dd/yyyy. Click to sort."},{"label":"User","value":"Who worked the time, shown as Last, First MI. Click to sort."},{"label":"Job","value":"The linked job number. A dash means no job is linked."},{"label":"Category","value":"The work category, like Production or Setup, or a dash if none. Click to sort."},{"label":"Duration","value":"How long it took, like '2h 15m' or '45m'. A green 'Running' label shows for active timers. Click to sort."},{"label":"Notes","value":"The note for the entry, trimmed to fit."},{"label":"Type","value":"A teal 'Timer' or gray 'Manual' label showing how the time was recorded."},{"label":"Actions","value":"A delete button for entries you can still change, or a lock icon for ones that are locked or in the past."}]},{"heading":"Clock Events","items":[{"label":"Event type","value":"What happened — clock in, clock out, break start, or break end."},{"label":"Time","value":"When the event happened."},{"label":"Scan method","value":"How the employee signed in — RFID, barcode, manual, or NFC. Optional."},{"label":"Source","value":"Which device or shop-floor kiosk recorded the event. Optional."},{"label":"Reason","value":"An optional note explaining the event, like 'early departure — doctor appointment'."}]},{"heading":"What Each Entry Records","items":[{"label":"Job","value":"The job this time is linked to, so its cost lands on the right job. Optional."},{"label":"Employee","value":"Who the entry belongs to. Set automatically to whoever created it."},{"label":"Date","value":"The day worked. Used for filtering and grouping into pay periods."},{"label":"Duration","value":"Total minutes worked. For timed entries this comes from the start and stop times."},{"label":"Start and stop times","value":"The exact times a timer began and ended. Blank for manual entries."},{"label":"Manual or timed","value":"Whether the time was typed in or tracked live with a timer. This is what the Timer/Manual label shows."},{"label":"Locked","value":"Marks an entry as locked by a manager or a closed pay period, which blocks edits and deletes."},{"label":"Operation","value":"Ties the time to a specific operation within a job, when you track time that finely. Optional."},{"label":"Kind of work","value":"For operation time, which stage it was — Setup, Run (the usual), Teardown, Inspection, Rework, Wait, or Other."},{"label":"Labor cost","value":"What the time cost — the employee's rate times the hours. Rolls into job costing."},{"label":"Overhead cost","value":"The share of shop overhead added on top of labor for this entry, so the job carries its fair share of the fixed costs."},{"label":"Sent to accounting","value":"Whether the office has passed this entry's hours to your accounting system yet. Blank until it goes across; after that, edits belong in accounting."}]},{"heading":"Admin Time Correction","items":[{"label":"Date","value":"A corrected date, if you're changing it."},{"label":"Duration","value":"A corrected length, in minutes, if you're changing it."},{"label":"Start and end times","value":"Corrected start and end times, if you're changing them."},{"label":"Category","value":"A corrected category, if you're changing it."},{"label":"Notes","value":"Corrected notes, if you're changing them."},{"label":"Job","value":"A corrected job link, if you're changing it."},{"label":"Reason (required)","value":"Why you're making this change. Saved to the audit trail so there's a record."}]},{"heading":"Buttons and Actions","items":[{"label":"Start Timer","value":"Opens the start timer panel. Shows only when no timer is running."},{"label":"Stop Timer","value":"Opens the stop timer panel with the elapsed time. Shows only while a timer is running, in place of Start Timer."},{"label":"Manual Entry","value":"Opens the manual entry panel. Your typing is auto-saved as a draft."},{"label":"Log Entry","value":"Saves the manual entry. Grayed out until the form is complete; a warning icon next to it lists anything missing."},{"label":"Start","value":"Starts the timer with the category and notes you chose."},{"label":"Stop Timer","value":"Stops the running timer and works out how long it ran."},{"label":"Delete","value":"Removes an entry you can still change, after you confirm. Only for today's or future entries."},{"label":"Cancel","value":"Closes the panel without saving."}]},{"heading":"Rules to Know","items":[{"label":"Date","value":"You have to pick a date for a manual entry."},{"label":"Hours","value":"Must be between 0 and 24."},{"label":"Minutes","value":"Must be between 0 and 59."},{"label":"Total time","value":"Hours plus minutes has to add up to more than zero, or you can't save."},{"label":"Starting a timer","value":"You can't start a new timer while one is already running — the Start Timer button hides until you stop it."},{"label":"Deleting","value":"You can only delete unlocked entries from today or later. Past entries show a lock icon instead."},{"label":"Correction reason","value":"An admin has to say why they made a correction."}]},{"heading":"Good to Know","items":[{"label":"No refresh needed","value":"Start or stop a timer and the page updates on its own — you never have to reload to see your new entry."},{"label":"The list stays current","value":"When you start a timer, it appears in the list right away; when you stop it, the finished time shows up. What you see is always up to date."},{"label":"One timer at a time","value":"You can only have one timer running. Stop the one you're on before you start another, so your hours don't overlap."},{"label":"Button tells your status","value":"The top button reads Start Timer when you're off the clock for a task, and Stop Timer when a timer is running — a quick way to check whether you're currently timing."},{"label":"Pick up on any device","value":"Start a timer at the kiosk and it's still running when you open the page on another screen. Your running timer follows you, so you won't accidentally start a second one."}]}]}"""
